import React, { useState, useEffect, useCallback } from 'react';
import Select from 'react-select';
import './AddPurchase.css';

// Move fetchMaterialChanges outside the component and wrap it with useCallback
const fetchMaterialChanges = async (materialid, vendors, setNewPurchase) => {
  if (materialid) {
    try {
      const response = await fetch(`http://localhost:8081/materialchangesAPI/${materialid}`);
      const data = await response.json();
      console.log('Data fetched:', data);

      if (data && data.price && data.vendor) {
        const selectedVendor = vendors.find((vendor) => vendor.vendorid === data.vendor);
        if (selectedVendor) {
          setNewPurchase((prevPurchase) => ({
            ...prevPurchase,
            price: data.price,
            vendor: data.vendor,
            vendorname: selectedVendor.name, // Set the selected vendor name instead of ID
          }));
        } else {
          setNewPurchase((prevPurchase) => ({
            ...prevPurchase,
            price: '',
            vendor: '',
            vendorname: '',
          }));
        }
      } else {
        // If no data available for the selected materialid, update the price and reset vendor to empty string
        setNewPurchase((prevPurchase) => ({
          ...prevPurchase,
          price: '',
          vendor: '',
          vendorname: '', // Reset the vendor value to an empty string
        }));
      }
    } catch (error) {
      console.error('Error fetching material changes:', error);
    }
  } else {
    // Clear the default values if no materialid is selected
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      price: '',
      vendor: '',
      vendorname: '', // Reset the vendor value to an empty string
    }));
  }
};

const AddPurchase = ({ handleAdd, locations, vendors }) => {
  const initialPurchaseState = {
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    price: '',
    vendor: '',
    vendorname: '',
  };

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);

  useEffect(() => {
    // Call the refactored fetchMaterialChanges function with dependencies passed
    fetchMaterialChanges(newPurchase.materialid, vendors, setNewPurchase);
  }, [newPurchase.materialid, vendors]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Convert the selected vendor name back to vendor ID before submitting to the API
    const selectedVendor = vendors.find((vendor) => vendor.name === newPurchase.vendorname);
    if (selectedVendor) {
      setNewPurchase((prevPurchase) => ({
        ...prevPurchase,
        vendor: selectedVendor.vendorid,
      }));
    }

    handleAdd(newPurchase);
    setNewPurchase(initialPurchaseState);
  };

  const handleVendorChange = (selectedOption) => {
    // Find the vendor with the given name in the vendors array
    const selectedVendor = vendors.find((vendor) => vendor.name === selectedOption?.label);
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '', // Set the selected vendor ID
      vendorname: selectedOption ? selectedOption.label : '', // Set the selected vendor name
    }));
  };

  const vendorOptions = vendors.map((vendor) => ({
    value: vendor.name,
    label: vendor.name,
  }));


  return (
    <form onSubmit={handleSubmit} className='add-purchase-form'>
      <div>
        <label>Location:</label>
        <select name="location" value={newPurchase.location} onChange={handleChange}>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={newPurchase.materialid} onChange={handleChange} />
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="materialname" value={newPurchase.materialname} readOnly />
      </div>
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={newPurchase.quantity} onChange={handleChange} />
      </div>
      <div>
        <label>Price:</label>
        <input
          type="text"
          name="price"
          value={newPurchase.price}
          onChange={handleChange}
        />
      </div>
      <div>
        <label>Vendor:</label>
        <Select
          options={vendorOptions}
          value={vendorOptions.find((option) => option.value === newPurchase.vendorname)} // Find the vendor option based on the selected vendor name
          onChange={handleVendorChange}
          placeholder="Select a Vendor"
          isSearchable // Enable search functionality
        />
      </div>
      <button type="submit" className="add_purchase_btn">Add Purchase</button>
    </form>
  );
};

export default AddPurchase;
